
import { defineComponent } from "vue";
import { useRouter } from "vue-router";
import { useStore } from "vuex";
import { SmileTwoTone,FireFilled } from "@ant-design/icons-vue";

export default defineComponent({
  components: {
    SmileTwoTone,
    FireFilled
  },
  setup() {
    const store = useStore();
    const router = useRouter();
    const log = (item: string) => {
      store.commit("removeRouter", item);
      // 删除缓存配置后跳转至首页
      if (store.state.routerList.length === 0) return;
      router.replace(store.state.routerList[0].value);
    };
    const Tabclick = (item: string) => {
      //console.log("点击");
      router.push({ name: item });
    };

    return {
      log,
      Tabclick,
    };
  },
});
