import { RouteRecordRaw } from "vue-router";



export const DeviceManage: RouteRecordRaw[] = [
  {
    path: 'device',
    name: 'device',
    component: () => import('../../views/deviceManage/device.vue'),
    meta: {
      name: '设备管理',
      keep: false,

    }
  },
  {
    path: 'labManage',
    name: 'labManage',
    component: () => import('../../views/deviceManage/labManage.vue'),
    meta: {
      name: '实验室管理',
      keep: false,

    }
  },
  {
    path: 'deviceType',
    name: 'deviceType',
    component: () => import('../../views/deviceManage/deviceType.vue'),
    meta: {
      name: '设备分类管理',
      keep: false,

    }
  },

]