
import { ref, defineComponent, reactive } from "vue";
import { updatePassword } from "@/server/http/api/admin";
import { useStore } from "vuex";
export default defineComponent({
  setup() {
    const store = useStore();

    const formRef = ref();
    const formState: any = reactive({
      username: "",
      oldPassword: "",
      newPassword: "",
    });
    let info: any = JSON.parse(store.state.userInfo);
    formState.username = info.username;
    const rules = {
      oldPassword: [
        { required: true, message: "内容不能为空", trigger: "blur" },
        {
          min: 6,
          max: 64,
          message: "密码不能小于6位",
          trigger: "blur",
        },
        {
          whitespace: true,
          message: "内容不含有空格",
          trigger: "change",
        },
      ],
      newPassword: [
        { required: true, message: "内容不能为空", trigger: "blur" },
        {
          min: 6,
          max: 64,
          message: "密码不能小于6位",
          trigger: "blur",
        },
        {
          whitespace: true,
          message: "内容不含有空格",
          trigger: "change",
        },
      ],
    };
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      formState.oldPassword = "";
      formState.newPassword = "";

      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;

          updatePassword(formState).then((res: any) => {
            visible.value = false;
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formRef,
      labelCol: { span: 4 },
      wrapperCol: { span: 14 },
      rules,
      formState,
    };
  },
});
