import http from '../http'
// 新增user
export function getadduser() {
  return http.get('/jkyErp/user/insert')
}
// 删除user
export function getdeluser() {
  return http.get('/jkyErp/user/delete')
}
// 修改user信息
export function postupdateuser(options: any) {
  return http.post('/jkyErp/user/updateUserInfo', options)
}
// 重置密码
export function getresetpas() {
  return http.get('/jkyErp/user/resetPassword')
}
// 新增角色
export function getaddrole() {
  return http.get('/jkyErp/role/addRole')
}
// 删除角色
export function getdelrole() {
  return http.get('/jkyErp/role/delete')
}
// 修改角色权限
export function getupdaterole() {
  return http.get('/jkyErp/role/updateRole')
}
// 全部组织架构信息
export function getAllDept() {
  return http.get('/jkyErp/dept/getAllDept')
}

// 用户检索展示
interface Uesrsearch {
  deptId?: number // 部门id
  username?: string // 登录名称
  mobile?: string // 手机号
  state?: string // 用户状态
}
export function getUserlist(options: Uesrsearch) {
  return http.post('/jkyErp/user/list', {
    deptId: options.deptId,
    username: options.username,
    mobile: options.mobile,
    state: options.state
  })
}

// 停用/启用用户
interface ChangeState {
  userId?: number,
  username: string
  state: string
}
export function postUpdateState(options: ChangeState) {
  return http.post('/jkyErp/user/changeState', {
    userId: options.userId,
    username: options.username,
    state: options.state
  })
}

// 重置密码
interface ResetPas {
  userId: number,
  username: string
}
export function postResetPassword(options: ResetPas) {
  return http.post('/jkyErp/user/resetPassword', {
    userId: options.userId,
    username: options.username
  })
}

// 角色列表
interface RoteList {
  roleRemark?: string
  roleName?: string
}
export function getRoleList(options: RoteList) {
  return http.get('/jkyErp/role/list', {
    roleRemark: options.roleRemark,
    roleName: options.roleName
  })
}
// 全部组织架构信息_无层级
export function getAllDepartment() {
  return http.get('/jkyErp/dept/getAllDepartment')
}

// 新增用户
export function addUser(options: any) {
  return http.post('/jkyErp/user/addUser', options)
}

// 查询人员信息
export function getUserList() {
  return http.get('/jkyErp/user/getUserList')
}

// 删除系统用户
export function userDelete(userId: any) {
  return http.post('/jkyErp/user/delete', { userId })
}
// 修改密码
export function updatePassword(options: any) {
  return http.post('/jkyErp/user/updatePassword', options)
}