// 样品修改
interface SampleUpdate {
  specs: string
  generation: string
  manufacturer: string
  sampleOrigin: string
  receivedDate: string
  sampleRequirement: string
  outward: string[]
  insertFlag: string
  outwardDescribe: string,
  sampleQuantity: string
}
export function update_sample(options: SampleUpdate) {

  return http.post('/jkyErp/sample/updateSample', {
    specs: options.specs,
    generation: options.generation,
    manufacturer: options.manufacturer,
    sampleOrigin: options.sampleOrigin,
    receivedDate: options.receivedDate,
    sampleRequirement: options.sampleRequirement,
    outward: options.outward.join('、') + '、' + options.outwardDescribe,
    insertFlag: options.insertFlag,
    sampleQuantity: options.sampleQuantity
  })
}

