
import { useRouter } from 'vue-router';
import bus from "../../../utils/bus";
import { getLogin, menulist } from '../../../server/http/api/user'
import { asyncRouter } from '../../../router/hooks/addrouter'
interface FormState {
  user: string;
  password: string;
  checked: boolean;
}
import { addRouter } from '../../../router/hooks/addrouter'
import { useStore } from 'vuex';
import { onMounted, onUnmounted, ref } from 'vue';
import { message } from "ant-design-vue";

const key = "loginloading";
export function login() {
  const hide1 = ref()

  let router = useRouter()
  let store = useStore()
  // ==================处理数据 添加 path属性 =》页面跳转使用========================
  function init(data: any) {
    data.forEach((item: any) => {
      if (item.catesFlag) {
        init(item.children)
      } else {
        let arr = asyncRouter.filter((val: any) => {
          return val.meta.name === item.treeName
        })
        if (arr.length > 0) {
          Object.assign(item, { path: arr[0].name })
        } else {
          Object.assign(item, { path: 'error' })
          console.warn(`没有“${item.treeName}”相关路由`);
        }
      }
    })
  }
  // ==========================================
  onMounted(() => {
    bus.on('subcommit', (val: FormState) => {
      const hide = message.loading({ content: "验证中...", key });
      getLogin(val).then((res: any) => {
        if (res.data.code == 200) {
          setTimeout(hide, 0);
          hide1.value = message.loading({ content: "初始化菜单...", key });

          store.commit('setuserInfo', res.data.userInfo)
          store.commit('setToken', res.data.token)
          return menulist()
        }
      }).then((datalist: any) => {
        setTimeout(hide1.value, 0);

        if (datalist.data.code === 200) {
          init(datalist.data.data)
          // //console.log('处理数据', datalist.data);
          let user = JSON.stringify(datalist.data.data)
          localStorage.setItem('user', user)
          // 分配动态路由
          addRouter()
          // 重置vuex缓存页面
          store.state.routerList = []
          // 跳转到默认页面
          router.push({ path: '/home' })
          const userInfo: any = JSON.parse(store.state.userInfo)

          message.success({
            content: `欢迎！，${userInfo.name}`,
          });
        }

      })
    })
  })
  onUnmounted(() => {
    bus.off('subcommit')
  })


}