import { createRouter, createWebHashHistory, RouteRecordRaw } from 'vue-router'
import store from '../store/index'
import Home from '../views/home/Home.vue'
import Login from '../views/login/Login.vue'
import { Amultitasking } from './ProductionManagement/Amultitasking'
const routes: Array<RouteRecordRaw> = [
    {
        path: '/login',
        redirect: to => {
            return { path: '/' }
        },
        component: Login
    },

    {
        path: '/',
        name: 'login',
        component: () => import(/* webpackChunkName: "about" */ '../views/login/Login.vue'),
        meta: {
            requireAuth: false
        }
    },
    {
        path: '/check',
        name: 'check',
        component: () => import(/* webpackChunkName: "about" */ '../views/check/Check.vue'),
        meta: {
            requireAuth: false

        }
    },
    {
        path: '/Error',
        name: 'Error',
        component: () => import(/* webpackChunkName: "about" */ '../views/error/Error.vue'),
        meta: {
            requireAuth: false

        }
    },
    // {
    //     path: '/PdfPreview',
    //     name: 'PdfPreview',
    //     component: () => import(/* webpackChunkName: "about" */ '../views/PdfPreview/Preview.vue'),
    //     meta: {
    //         requireAuth: false

    //     }
    // }

]



const router = createRouter({
    history: createWebHashHistory(),
    routes: [...routes]
})



