//   //console.log(store.state);

// });
router.afterEach((to: any) => {

    // 页面是否缓存
    if (to.meta.keep) {
        // 获取组件名称
        let name = to.matched[1] && to.matched[1].components.default.name;
        store.commit('activeTab', name)
        if (!name) return;
        store.commit('addRouter', { value: name, label: to.matched[1].meta.name }); // 保存组件名称
    } else {
        store.commit('activeTab', '')
    }


});


router.beforeEach((to, from, next) => {

    if (to.meta.requireAuth) {
        let data = localStorage.getItem('user')
        if (data) {
            let user = JSON.parse(data)
            let routerlist: any = []
            function init(arr: any) {
                arr.forEach((item: any) => {
                    if (item.catesFlag) {
                        init(item.children)
                    } else {
                        routerlist.push(item.path)


                    }
                })
            };
            init(user)
            let auto = routerlist.filter((val: any) => {
                return val === to.name
            })

            if (auto.length > 0) {
                next()
            } else {
                next('/Error')
            }
        } else {
            next('/login')
        }
    } else {
        next()
    }
})



export default router
