
import {
  UserOutlined,
  VideoCameraOutlined,
  UploadOutlined,
  MenuUnfoldOutlined,
  MenuFoldOutlined,
} from "@ant-design/icons-vue";
import {
  computed,
  defineComponent,
  reactive,
  ref,
  Ref,
  toRefs,
  watch,
} from "vue";
import { useStore } from "vuex";
import Tabkeep from "../../components/Tabkeep/Tabkeep.vue";
import User from "../../components/user/User.vue";
import { init_user_list } from "./hooks/initUserList";
import { nanoid } from "nanoid";
export default defineComponent({
  name: "home",
  components: {
    UserOutlined,
    VideoCameraOutlined,
    UploadOutlined,
    MenuUnfoldOutlined,
    MenuFoldOutlined,
    User,
    Tabkeep,
  },
  setup() {
    let store = useStore();
    let data = reactive({
      user_list: [],
      marginLeft: "200px",
      collapsed: false,
      trigger: "216px",
      current: "mail",
      titleed: false,
    });
    // ===== 初始化用户菜单列表====
    data.user_list = init_user_list();
    // ============================

    let collapseClick = (collapsed: any, type: any) => {
      //console.log(collapsed, type);
    };

    watch(
      () => data.collapsed,
      (newval, o) => {
        if (newval) {
          data.marginLeft = "80px";
          data.trigger = "96px";
          data.titleed = true;
        } else {
          data.marginLeft = "200px";
          data.trigger = "216px";
          setTimeout(() => {
            data.titleed = false;
          }, 110);
        }
      }
    );
    return {
      selectedKeys: ref<string[]>(["1"]),
      collapseClick,
      ...toRefs(data),
    };
  },
});
