import { createStore } from 'vuex'

export default createStore({
  state: {
    routerList: [], // 组件名称数组，也可尝试Set对象
    activeRouter: '',
    token: localStorage.getItem('token') ? localStorage.getItem('token') : '',
    userInfo: localStorage.getItem('userInfo') ? localStorage.getItem('userInfo') : ''
  },
  mutations: {
    addRouter(state: any, name: any) {
      // //console.log('push', name);
      if (!state.routerList.find((it: any) => it.value === name.value)) {
        state.routerList.push(name);
      }
    },
    // 移除组件名称
    removeRouter(state: any, name: any) {
      // //console.log('remove', name);
      state.routerList = state.routerList.filter((it: any) => it.value !== name);
    },
    activeTab(state: any, name: any) {
      state.activeRouter = name
    },
    // 设置token
    setToken(state, token) {
      state.token = token;
      localStorage.setItem("token", token);     //存储token
    },
    // 删除token
    delToken(state) {
      state.token = '';
      localStorage.removeItem("token");    //删除token
    },
    // 设置userInfo
    setuserInfo(state, userInfo) {
      state.userInfo = JSON.stringify(userInfo);
      localStorage.setItem("userInfo", JSON.stringify(userInfo));     //存储token
    },
    // 删除userInfo
    deluserInfo(state) {
      state.userInfo = '';
      localStorage.removeItem("userInfo");    //删除token
    }

  },
  getters: {
    // 需要缓存的组件
    includeList(state) {
      let list: any = [];
      state.routerList.map((item: any) => {
        list.push(item.value)
      })
      return list
    }
  },
  actions: {
  },
  modules: {
  }
})
