import axios from 'axios'
import config from './config'
import store from '../../store/index'
import { message } from 'ant-design-vue';
let app = axios.create({
  baseURL: `${config.baseURL}${config.proxyName}`,
  headers: {
    // ContentType: 'application/json',
    timeout: '50000'
  }
})




// 请求前置
app.interceptors.request.use((config: any) => {
  // if (localStorage.getItem('token') && config.url !== '/jkyErp/userLogin/login') {
  config.headers.common['Authorization'] = `${localStorage.getItem('token')}`   //此处的XX-Token要根据登录接口中请求头的名字来写

  // }
  // config.headers.common['Authorization'] = `login_token_b5170260-5e2a-4d11-b4bf-0a846e8b7228`
  return config
}, (err) => {
  if (err) {
    message.error(
      `请求错误:${err}`
    );
    //console.log('错误！！！');
  }

  return Promise.resolve(err)
})

// 请求后置
app.interceptors.response.use((response) => {

  if (response.data.code === 200) {
    // if (
    //   response.data.msg
    // ) {
    //   // message.success(
    //   //   response.data.msg
    //   // );
    // }


    // if (response.data.data && response.data.data['403']) {
    //   message.warning(response.data.data['403'])
    // }
    if (response.data.data === null) {
      message.success(
        response.data.msg
      );
    }
    if (typeof response.data.data === 'string') {
      message.success(
        response.data.data
      );
    }


  } else if (response.data.code === 500) {
    if (
      response.data.msg
    ) {
      message.error(
        response.data.msg
      )
    }
  } else {
    if (
      response.data.msg
    ) message.error(
      response.data.msg
    );
  }
  return response
}, (err) => {
  message.error(
    `网络异常:${err}`
  );
  //console.log('网络异常！！！');
  return Promise.resolve(err)
})


export function post(url: string, params?: any) {
  return new Promise((resolve, reject) => {
    app.post(url, params).then(
      res => {
        resolve(res)
      },
      err => {
        reject(err)
      }
    )
  })
}
export function get(url: string, params?: any) {
  return new Promise((resolve, reject) => {
    app.get(url, { params }).then(
      res => {
        resolve(res)
      },
      err => {
        reject(err)
      }
    )
  })
}


export default {
  post,
  get,

}

