import { RouteRecordRaw, useRouter } from 'vue-router'
import router from '../index'
import { admin } from '../admin'
import { ATaskdelegation } from '../ProductionManagement/ATaskdelegation'
import { ATestdetection } from '../ProductionManagement/ATestdetection'
import { Amultitasking } from '../ProductionManagement/Amultitasking'
import { ATaskdelegationPage, ATestdetectionPage, AmultitaskingPage } from '../ProductionManagement/notMenuPage'
import Home from '../../views/home/Home.vue'
import { team } from '../ProductionManagement/TeamManage'
import { DeviceManage } from '../ProductionManagement/DeviceManage'
import { Product } from '../ProductionManagement/Product'
import { pathenn } from '../ProductionManagement/pathenn'
import { partenr } from '../ProductionManagement/partenr'

export const asyncRouter: RouteRecordRaw[] = [
  {
    path: 'index',
    name: 'index',
    component: () => import('../../views/index/Index.vue'),
    meta: {
      name: '首页',
      requireAuth: true
    }
  },
  {
    path: 'error',
    name: 'error',
    component: () => import('../../views/error/Error.vue'),
    meta: {
      name: '403',
      requireAuth: false
    }
  },
  ...admin,
  ...ATaskdelegation,
  ...ATestdetection,
  // 任务处理
  ...Amultitasking,
  //团队管理
  ...team,
     //设备管理
  ...DeviceManage,
  //产品管理
  ...Product,
  // 专利管理
  ...pathenn,
  //合作伙伴
  ...partenr
]

const notMenuPage: any = {
  ...ATaskdelegationPage,
  ...ATestdetectionPage,
  ...AmultitaskingPage
}



let routerlist: any = []
function init(arr: any) {
  arr.forEach((item: any) => {
    if (item.catesFlag) {
      init(item.children)
    } else {
      let routerObj = asyncRouter.filter((level: any) => {
        return level.name === item.path
      })
      // //console.log(routerObj[0].meta);
      try {
        if (routerObj[0].meta && routerObj[0].meta.rolePage) {
          let rolePage: any = routerObj[0].meta.rolePage;
          rolePage.map((item: any) => {
            routerlist.push(notMenuPage[item]
            )
          })
        }
      } catch (error) {
        localStorage.removeItem('user')
      }

      routerlist.push(routerObj[0])
    }
  })
};


export function addRouter() {
  let data: any = localStorage.getItem('user') || undefined
  if (data) {
    let user: any = JSON.parse(data);
    if (user) {


      init(user);
      router.addRoute({
        path: '/home',
        name: 'home',
        component: Home,
        redirect: to => {
          return { name: 'index' }
        },
        children: []
      })
      routerlist.map((item: any) => {
        router.addRoute('home', item)
      })
    }
  } else {

  }

}